#include <stdio.h>

int main()
{
    int n = 2;
    char tekst[] = "Ovo je neki primjer";
    char* s = tekst;
    char* pocetak;
    int brojac = 0;

    if (n <= 0) {
        printf("Nevalidno n.");
        return 1;
    }

    while (*s != '\0') {
        brojac++;
        if (brojac % n == 0) {
            pocetak = s;
            /* pomjeramo ostatak stringa preko n-tog karaktera */
            while (*pocetak != '\0') {
                *pocetak = *(pocetak + 1);
                pocetak++;
            }
        } else {
            s++;
        }
    }

    printf("%s\n", tekst);
    return 0;
}
